Derive subsystem health from existing entity hooks:

```typescript
import { usePulseEnabled, useSchedules, useRuns } from '@/layers/entities/pulse';
import { useRelayEnabled, useRelayAdapters, useAggregatedDeadLetters } from '@/layers/entities/relay';
import { useMeshStatus } from '@/layers/entities/mesh';

interface SubsystemStatus {
  pulse: {
    enabled: boolean;
    scheduleCount: number;
    nextRunIn: string | null; // formatted relative time
    failedRunCount: number; // from last 24h
  };
  relay: {
    enabled: boolean;
    adapterCount: number;
    connectedNames: string[]; // display names of connected adapters
    deadLetterCount: number;
  };
  mesh: {
    totalAgents: number;
    offlineCount: number; // unreachableCount from MeshStatus
  };
}

export function useSubsystemStatus(): SubsystemStatus {
  const pulseEnabled = usePulseEnabled();
  const { data: schedules } = useSchedules();
  const { data: failedRuns } = useRuns({ status: 'failed' });
  const relayEnabled = useRelayEnabled();
  const { data: adapters } = useRelayAdapters();
  const { data: deadLetters } = useAggregatedDeadLetters();
  const { data: meshStatus } = useMeshStatus();

  // Pulse: count schedules, filter failed runs to last 24h, compute next run time
  // For nextRunIn: find the schedule with the earliest next run, format as relative time (e.g., "47m", "2h")
  // Relay: count adapters, extract connected adapter display names, sum dead letter counts
  // Mesh: use totalAgents and unreachableCount from meshStatus
  // Return disabled state for Pulse/Relay when their feature flag is off
}
```

## 2. `use-session-activity.ts`

Derive 7-day session count sparkline data:

```typescript
import { useMemo } from 'react';
import { useSessions } from '@/layers/entities/session';

export function useSessionActivity(): number[] {
  const { data: sessions } = useSessions();

  return useMemo(() => {
    // Create 7 daily buckets from 6 days ago through today
    // For each session, bucket its createdAt into the corresponding day
    // Return number[] of length 7
    const buckets = Array(7).fill(0) as number[];
    if (!sessions) return buckets;

    const now = new Date();
    const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    for (const session of sessions) {
      const created = new Date(session.createdAt);
      const diffDays = Math.floor((startOfToday.getTime() - new Date(created.getFullYear(), created.getMonth(), created.getDate()).getTime()) / (1000 * 60 * 60 * 24));
      if (diffDays >= 0 && diffDays < 7) {
        buckets[6 - diffDays]++;
      }
    }
    return buckets;
  }, [sessions]);
}
```

