## 4. `ActivitySparkline.tsx`

Pure SVG component, no charting library:

```tsx
interface ActivitySparklineProps {
  data: number[]; // 7 values, one per day
  className?: string;
}

export function ActivitySparkline({ data, className }: ActivitySparklineProps) {
  const max = Math.max(...data, 1); // avoid division by zero
  const barWidth = 10;
  const gap = 4;
  const height = 30;

  return (
    <svg viewBox="0 0 100 30" className={cn('text-muted-foreground', className)}>
      {data.map((value, i) => {
        const barHeight = (value / max) * height;
        return (
          <rect
            key={i}
            x={i * (barWidth + gap) + 1}
            y={height - barHeight}
            width={barWidth}
            height={Math.max(barHeight, 1)} // minimum 1px for visibility
            rx={2}
            fill="currentColor"
            opacity={0.6}
          />
        );
      })}
    </svg>
  );
}
```

