## 1. `use-active-sessions.ts`

Filter and enrich sessions:

```typescript
import { useMemo } from 'react';
import { useSessions } from '@/layers/entities/session';
import { useResolvedAgents } from '@/layers/entities/agent';

interface ActiveSession {
  id: string;
  title: string;
  cwd: string;
  agentName: string;
  agentEmoji: string;
  agentColor: string;
  lastActivity: string; // lastMessagePreview, truncated to 1 line
  elapsedTime: string; // formatted from createdAt
  status: 'active' | 'idle'; // based on updatedAt recency
}

export function useActiveSessions(): { sessions: ActiveSession[]; totalCount: number } {
  const { data: allSessions } = useSessions();

  // Filter to sessions updated within the last 2 hours
  const recentSessions = useMemo(() => {
    if (!allSessions) return [];
    const twoHoursAgo = Date.now() - 2 * 60 * 60 * 1000;
    return allSessions.filter((s) => new Date(s.updatedAt).getTime() > twoHoursAgo);
  }, [allSessions]);

  // Extract unique cwds for agent resolution
  const uniquePaths = useMemo(
    () => [...new Set(recentSessions.map((s) => s.cwd))],
    [recentSessions],
  );
  const { data: agents } = useResolvedAgents(uniquePaths);

  const sessions = useMemo(() => {
    const fiveMinutesAgo = Date.now() - 5 * 60 * 1000;
    return recentSessions
      .map((session) => {
        const agent = agents?.[session.cwd];
        const updatedTime = new Date(session.updatedAt).getTime();
        const createdTime = new Date(session.createdAt).getTime();
        const elapsed = Date.now() - createdTime;
        return {
          id: session.id,
          title: session.title ?? session.id,
          cwd: session.cwd,
          agentName: agent?.name ?? session.cwd.split('/').pop() ?? 'Agent',
          agentEmoji: agent?.emoji ?? '',
          agentColor: agent?.color ?? '',
          lastActivity: session.lastMessagePreview ?? '',
          elapsedTime: formatElapsed(elapsed),
          status: updatedTime > fiveMinutesAgo ? 'active' : 'idle',
        } satisfies ActiveSession;
      })
      .slice(0, 6); // Cap at 6
  }, [recentSessions, agents]);

  return { sessions, totalCount: recentSessions.length };
}

function formatElapsed(ms: number): string {
  const minutes = Math.floor(ms / 60000);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ${minutes % 60}m`;
  return `${Math.floor(hours / 24)}d`;
}
```

Status heuristic: sessions updated in the last 5 minutes are "active", others are "idle". This is a proxy since per-session streaming state is only known for the current session.

