## 1. `use-attention-items.ts`

Derives attention items from multiple entity hooks:

```typescript
import { useMemo, useCallback } from 'react';
import { useSessions } from '@/layers/entities/session';
import { useRuns } from '@/layers/entities/pulse';
import { useAggregatedDeadLetters } from '@/layers/entities/relay';
import { useMeshStatus } from '@/layers/entities/mesh';
import { useNavigate } from '@tanstack/react-router';
import { useAppStore } from '@/layers/shared/model';
import type { LucideIcon } from 'lucide-react';
import { Clock, XCircle, Mail, WifiOff } from 'lucide-react';

export interface AttentionItem {
  id: string;
  type: 'stalled-session' | 'failed-run' | 'dead-letter' | 'offline-agent';
  icon: LucideIcon;
  title: string;
  description: string;
  timestamp: string; // ISO
  action: {
    label: string;
    onClick: () => void;
  };
  severity: 'warning' | 'error';
}

export function useAttentionItems(): AttentionItem[] {
  const { data: sessions } = useSessions();
  const { data: failedRuns } = useRuns({ status: 'failed' });
  const { data: deadLetters } = useAggregatedDeadLetters();
  const { data: meshStatus } = useMeshStatus();
  const navigate = useNavigate();
  const setRelayOpen = useAppStore((s) => s.setRelayOpen);
  const setMeshOpen = useAppStore((s) => s.setMeshOpen);
  const setPulseOpen = useAppStore((s) => s.setPulseOpen);

  return useMemo(() => {
    const items: AttentionItem[] = [];
    const now = Date.now();
    const twentyFourHoursAgo = now - 24 * 60 * 60 * 1000;
    const thirtyMinutesAgo = now - 30 * 60 * 1000;

    // Stalled sessions: updated >30min ago (proxy for waiting/stalled state)
    if (sessions) {
      for (const session of sessions) {
        const updatedAt = new Date(session.updatedAt).getTime();
        if (updatedAt < thirtyMinutesAgo && updatedAt > twentyFourHoursAgo) {
          const minutesAgo = Math.floor((now - updatedAt) / 60000);
          items.push({
            id: `stalled-${session.id}`,
            type: 'stalled-session',
            icon: Clock,
            title: `Session "${session.title ?? session.id.slice(0, 8)}" idle`,
            description: `Session idle for ${minutesAgo} minutes`,
            timestamp: session.updatedAt,
            action: {
              label: 'Open →',
              onClick: () => navigate({ to: '/session', search: { session: session.id, dir: session.cwd } }),
            },
            severity: 'warning',
          });
        }
      }
    }

    // Failed Pulse runs from last 24h
    if (failedRuns) {
      for (const run of failedRuns) {
        const runTime = new Date(run.createdAt ?? run.startedAt).getTime();
        if (runTime > twentyFourHoursAgo) {
          items.push({
            id: `failed-${run.id}`,
            type: 'failed-run',
            icon: XCircle,
            title: `Pulse: "${run.scheduleName ?? run.id}" failed`,
            description: `Pulse run failed`,
            timestamp: run.createdAt ?? run.startedAt,
            action: {
              label: 'View →',
              onClick: () => setPulseOpen(true),
            },
            severity: 'error',
          });
        }
      }
    }

    // Dead Relay letters with count > 0
    if (deadLetters) {
      for (const group of deadLetters) {
        if (group.count > 0) {
          items.push({
            id: `dead-letter-${group.id ?? group.subject}`,
            type: 'dead-letter',
            icon: Mail,
            title: `${group.count} undeliverable Relay messages`,
            description: `Dead letters for ${group.subject ?? 'unknown subject'}`,
            timestamp: group.lastAttempt ?? new Date().toISOString(),
            action: {
              label: 'View →',
              onClick: () => setRelayOpen(true),
            },
            severity: 'warning',
          });
        }
      }
    }

    // Offline Mesh agents
    if (meshStatus && meshStatus.unreachableCount > 0) {
      items.push({
        id: 'offline-agents',
        type: 'offline-agent',
        icon: WifiOff,
        title: `${meshStatus.unreachableCount} agent${meshStatus.unreachableCount > 1 ? 's' : ''} offline`,
        description: `${meshStatus.unreachableCount} mesh agents unreachable`,
        timestamp: new Date().toISOString(),
        action: {
          label: 'View →',
          onClick: () => setMeshOpen(true),
        },
        severity: 'error',
      });
    }

    // Sort by timestamp, most recent first
    items.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

    return items;
  }, [sessions, failedRuns, deadLetters, meshStatus, navigate, setRelayOpen, setMeshOpen, setPulseOpen]);
}
```

Note: `tool-approval` type is deferred — cross-session tool approval state is not exposed by the server API in v1.

## 2. `AttentionItem.tsx`

Single attention row:

```tsx
import { Button } from '@/layers/shared/ui';
import { motion } from 'motion/react';
import type { AttentionItem as AttentionItemType } from '../model/use-attention-items';

const staggerItem = {
  initial: { opacity: 0, y: 8 },
  animate: { opacity: 1, y: 0 },
} as const;

interface AttentionItemProps {
  item: AttentionItemType;
}

export function AttentionItemRow({ item }: AttentionItemProps) {
  const Icon = item.icon;
  const relativeTime = formatRelativeTime(item.timestamp);

  return (
    <motion.div
      variants={staggerItem}
      className="flex items-center gap-3 py-1.5"
    >
      <Icon className="size-(--size-icon-sm) shrink-0 text-muted-foreground" />
      <span className="text-sm text-foreground flex-1 truncate">{item.description}</span>
      <span className="text-xs text-muted-foreground tabular-nums shrink-0">{relativeTime}</span>
      <Button variant="ghost" size="sm" className="h-6 text-xs shrink-0" onClick={item.action.onClick}>
        {item.action.label}
      </Button>
    </motion.div>
  );
}

function formatRelativeTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const minutes = Math.floor(diff / 60000);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h`;
  return `${Math.floor(hours / 24)}d`;
}
```

Row anatomy: Icon (16px, `size-(--size-icon-sm)`) | Description (`text-sm text-foreground`) | Relative timestamp (`text-xs text-muted-foreground tabular-nums`) | Action button (`variant="ghost"` with `text-xs`).

## 3. `NeedsAttentionSection.tsx`

Conditional section that renders nothing when empty:

```tsx
import { AnimatePresence, motion } from 'motion/react';
import { useAttentionItems } from '../model/use-attention-items';
import { AttentionItemRow } from './AttentionItem';

const conditionalSection = {
  initial: { height: 0, opacity: 0 },
  animate: { height: 'auto', opacity: 1 },
  exit: { height: 0, opacity: 0 },
  transition: { duration: 0.25, ease: [0, 0, 0.2, 1] },
} as const;

const staggerContainer = {
  animate: { transition: { staggerChildren: 0.04 } },
} as const;

export function NeedsAttentionSection() {
  const items = useAttentionItems();

  return (
    <AnimatePresence initial={false}>
      {items.length > 0 && (
        <motion.section
          key="attention"
          {...conditionalSection}
          className="overflow-hidden"
        >
          <h2 className="text-xs tracking-widest font-medium uppercase text-amber-600 dark:text-amber-500 mb-3">
            Needs Attention
          </h2>
          <motion.div variants={staggerContainer} initial="initial" animate="animate">
            {items.slice(0, 8).map((item) => (
              <AttentionItemRow key={item.id} item={item} />
            ))}
          </motion.div>
        </motion.section>
      )}
    </AnimatePresence>
  );
}
```

Visibility rule: Renders nothing when `items.length === 0` — zero DOM presence. Uses `AnimatePresence initial={false}` so it doesn't animate on page load when empty.

Section header: `text-xs tracking-widest font-medium uppercase` with amber color (`text-amber-600 dark:text-amber-500`).

Animation: Section entrance: `height: 0 → 'auto'`, `opacity: 0 → 1`, duration 0.25s, ease `[0, 0, 0.2, 1]`. Individual items: stagger with `staggerChildren: 0.04`, limited to first 8 items.

