```tsx
import type { ActivityGroup } from '../model/use-activity-feed';
import { ActivityFeedItem } from './ActivityFeedItem';

interface ActivityFeedGroupProps {
  group: ActivityGroup;
  lastVisitedAt: string | null;
  showSeparator?: boolean; // show "Since your last visit" separator
}

export function ActivityFeedGroup({ group, lastVisitedAt, showSeparator }: ActivityFeedGroupProps) {
  // Find the index where events transition from "new" to "old"
  const separatorIndex = lastVisitedAt
    ? group.events.findIndex((e) => new Date(e.timestamp) <= new Date(lastVisitedAt))
    : -1;

  return (
    <div>
      <h3 className="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2 mt-4">
        {group.label}
      </h3>
      <div className="space-y-0.5">
        {group.events.map((event, idx) => (
          <div key={event.id}>
            {showSeparator && idx === separatorIndex && separatorIndex > 0 && (
              <SinceLastVisitSeparator lastVisitedAt={lastVisitedAt!} />
            )}
            <ActivityFeedItem
              event={event}
              isNew={lastVisitedAt ? new Date(event.timestamp) > new Date(lastVisitedAt) : false}
            />
          </div>
        ))}
      </div>
    </div>
  );
}

function SinceLastVisitSeparator({ lastVisitedAt }: { lastVisitedAt: string }) {
  const diff = Date.now() - new Date(lastVisitedAt).getTime();
  const hours = Math.floor(diff / 3600000);
  const timeAgo = hours < 24 ? `${hours} hours ago` : `${Math.floor(hours / 24)} days ago`;

  return (
    <div className="flex items-center gap-3 py-2">
      <div className="flex-1 border-t border-muted-foreground/20" />
      <span className="text-xs text-muted-foreground shrink-0">
        Since your last visit · {timeAgo}
      </span>
      <div className="flex-1 border-t border-muted-foreground/20" />
    </div>
  );
}
